const item = $json;

// Solo bloqueamos si es TRASH absoluto o si ya fue rechazado por Guard
if (item.category === 'trash' || item.trash === true) return [];

let score = 0;
// Scoring dinámico para el feed
if (item.category === 'evento') score += 50;
if (item.category === 'plaza') score += 20;
if (item.city && item.city !== 'Global') score += 15;
if ((item.text_es || '').length > 200) score += 10;

return { ...item, final_score: score };

const item = $input.first().json;
function escapeHTML(text) { return String(text||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function formatContact(val) { 
  if (!val) return 'No disponible';
  const str = String(val).trim();
  if (/[a-zA-Z]/.test(str)) return str; 
  const s = str.replace(/[^0-9]/g, ''); 
  return s.length >= 7 ? `+${s}` : str; 
}

const displayContact = formatContact(item.contact || item.final_contact);
const categoryStr = (item.category === 'plaza') ? 'Plazas' : 'Eventos';

// Solo mantenemos el grupo español activado
const langs = [
  { code: 'ES', tg: '-5283488138', wa: '120363425790792660@g.us', title: item.title_es, text: item.text_es, tag: 'Remitente' }
];

const results = [];
for (const l of langs) {
  function formatOutputContact(val, mode) {
    if (!val) return 'No disponible';
    if (String(val).startsWith('tg_id_')) {
      const id = val.replace('tg_id_', '');
      return mode === 'html' ? `<a href="tg://user?id=${id}">Chat Directo</a>` : `ID: ${id}`;
    }
    if (/[a-zA-Z]/.test(val)) {
       const user = String(val).replace('@', '');
       return mode === 'html' ? `<a href="https://t.me/${user}">@${user}</a>` : `@${user}`;
    }
    const s = String(val).replace(/[^0-9]/g, '');
    return s.length >= 7 ? `+${s}` : val;
  }

  const tgContact = formatOutputContact(item.contact || item.final_contact, 'html');
  const waContact = formatOutputContact(item.contact || item.final_contact, 'text');

  const tgText = `<b>${escapeHTML(l.title)}</b>\n🏷️ <b>${categoryStr}</b>\n📍 <b>${escapeHTML(item.city)}</b>\n💰 <b>${escapeHTML(item.budget)}</b>\n\n${escapeHTML(l.text)}\n\n👤 <b>${l.tag}:</b> ${tgContact}\n🔌 <b>Fuente:</b> ${escapeHTML(item.platform)}`;
  const waText = `*📢 ${l.title}*\n📍 *${item.city}* | 💰 *${item.budget}*\n\n${l.text}\n\n👤 *${l.tag}:* ${waContact}\n🔌 *Fuente:* ${item.platform}`;

  results.push({
    json: { ...item, route_lang: l.code, tg_chat: l.tg, tg_text: tgText, wa_chat: l.wa, wa_text: waText }
  });
}
return results;

// DYNAMIC ROUTING ENGINE v5
const item = $json;
const category = String(item.category || '').toLowerCase();
const city = String(item.city || '').toLowerCase();
const text = String(item.text_es || '').toLowerCase();

// Solo procesamos EVENTOS para routing VIP
if (category !== 'evento') return [];

// CONFIGURACIÓN DINÁMICA DE DESTINOS
const routingTable = {
  "madrid": [
    { to: "34664266926@s.whatsapp.net", label: "MADRID" },
    { to: "34603346859@s.whatsapp.net", label: "MADRID" }
  ],
  "ibiza": [
    { to: "34662058447@s.whatsapp.net", label: "IBIZA" },
    { to: "34642107796@s.whatsapp.net", label: "IBIZA" }
  ],
  "miami": [
    { to: "17862812324@s.whatsapp.net", label: "MIAMI" },
    { to: "525532110621@s.whatsapp.net", label: "MIAMI" }
  ],
  "paris": [
    { to: "33744156314@s.whatsapp.net", label: "PARIS" }
  ]
};

// Búsqueda de destinos (soporta ciudad exacta o mención en texto)
let targets = [];
for (const [key, dests] of Object.entries(routingTable)) {
  if (city.includes(key) || text.includes(key)) {
    targets = [...targets, ...dests];
  }
}

// Eliminar duplicados de destinos por si city y text coinciden
const uniqueTargets = Array.from(new Set(targets.map(t => t.to)))
  .map(to => targets.find(t => t.to === to));

return uniqueTargets.map(t => ({
  json: { 
    ...item, 
    target_wa: t.to, 
    city_label: t.label 
  }
}));

const payload = $input.first().json;
const item = payload.body || payload;
const textBody = item.text || item.message?.text || '';

function findUsername(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const contact = obj.contact || obj.sender || obj.from || '';
  if (typeof contact === 'string') {
    if (contact.includes('t.me/')) return contact.split('t.me/')[1];
    if (contact.startsWith('tg_id_')) return contact;
    if (contact.startsWith('@')) return contact;
    if (/^\d{7,15}$/.test(contact)) return 'tg_id_' + contact;
  }
  const id = obj.id || obj.from?.id || obj.message?.from?.id;
  if (id && /^\d+$/.test(String(id))) return 'tg_id_' + id;
  return null;
}

let sc = findUsername(item);
if (sc && !sc.startsWith('tg_id_')) {
  sc = sc.trim();
  if (!sc.startsWith('@')) sc = '@' + sc;
}

const sourceChatId = item.chatId || item.message?.chat?.id || '';
const isGroup = String(sourceChatId).startsWith('-');

return {
  ...item,
  platform: 'Telegram',
  sender_contact: sc || 'No_Username',
  final_contact: sc || 'No_Username',
  source_chat_id: sourceChatId,
  texto_limpio: textBody.trim(),
  looksValuable: textBody.length > 5 && sc
};

const item = $input.first().json;
const body = item.body || item;
const msgs = body.messages || [];
const msg = msgs[0] || {};
const textBody = msg.text?.body || msg.caption || body.text || body.caption || '';

function getPhone(val) {
  if (!val) return null;
  let s = String(typeof val === 'object' ? (val.id || val.phone || val.number) : val);
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7) ? digits : null;
}

const sc = getPhone(msg.from) || getPhone(body.from) || "No disponible";
const sourceChatId = msg.chat_id || body.chatId || null;

return {
  ...item,
  platform: "WhatsApp",
  sender_contact: sc,
  final_contact: sc,
  source_chat_id: sourceChatId,
  texto_limpio: textBody.trim(),
  looksValuable: textBody.length > 5
};

const results = [];
const HARD_BLOCK = new Set(["crypto", "binance", "casino", "usdt", "bitcoin", "wallet", "trading", "ganar dinero", "инди", "контент", "onlyfans", "вирт", "sugar baby", "sugar daddy", "anal", "masaje erotico", "ingles", "english"]);
const BANNED_PREFIXES = ["58", "57", "92", "91", "62", "63"];

function norm(v) { return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio);
  const sender = String(data.final_contact).replace(/\D/g, "");

  let rejectReason = null;
  if (BANNED_PREFIXES.some(p => sender.startsWith(p))) rejectReason = "prefix_banned";
  else if (HARD_BLOCK.has(text)) rejectReason = "hard_block_match";

  results.push({ json: { ...data, looksValuable: !rejectReason, reject_reason: rejectReason } });
}
return results;

const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];

const now = Date.now();
const TTL = 86400000;
store.history = store.history.filter(h => now - h.time < TTL);

for (const item of $input.all()) {
  const fp = String(item.json.texto_limpio).substring(0, 100);
  if (!store.history.some(h => h.fp === fp)) {
    store.history.push({ time: now, fp });
    results.push(item);
  }
}
return results;

try {
  const input = $input.first().json;
  let rawText = input.text || input.output || input.response || input.result || "";

  if (typeof rawText !== 'string') rawText = JSON.stringify(rawText);

  let cleaned = rawText.replace(/```json/gi, '').replace(/```/gi, '').trim();
  let start = cleaned.indexOf('{');
  let end = cleaned.lastIndexOf('}');

  if (start === -1 || end === -1) {
    return [{ json: { ...input, trash: true, category: 'trash', debug_error: 'No JSON object delimiters found' } }];
  }

  let jsonStr = cleaned.substring(start, end + 1);
  // Reemplazamos saltos de línea reales por espacios para evitar fallos de JSON.parse
  jsonStr = jsonStr.replace(/\n/g, ' ').replace(/\r/g, ' ');

  let parsed = JSON.parse(jsonStr);
  return [{ json: { ...input, ...parsed, trash: parsed.trash === true || parsed.category === 'trash' } }];
} catch(e) {
  return [{ json: { ...$input.first().json, trash: true, category: 'trash', parse_error: e.message } }];
}
